import java.io.Serializable;
import java.util.*;

public class SamlUserDetails implements UserDetails, Serializable {

    private static final long serialVersionUID = 1L;

    private final String nameId;
    private final String sessionIndex;
    private final Map<String, List<String>> attributes;
    private final Set<GrantedAuthority> authorities;

    public SamlUserDetails(String nameId, String sessionIndex,
                           Map<String, List<String>> attributes,
                           Collection<? extends GrantedAuthority> authorities) {
        this.nameId = Objects.requireNonNull(nameId, "nameId must not be null");
        this.sessionIndex = sessionIndex;
        this.attributes = Collections.unmodifiableMap(new LinkedHashMap<>(attributes));
        this.authorities = Collections.unmodifiableSet(new LinkedHashSet<>(authorities));
    }

    public String getNameId() { return nameId; }
    public String getSessionIndex() { return sessionIndex; }
    public Map<String, List<String>> getAttributes() { return attributes; }

    public String getFirstAttribute(String name) {
        List<String> values = attributes.get(name);
        return (values != null && !values.isEmpty()) ? values.get(0) : null;
    }

    @Override public Collection<? extends GrantedAuthority> getAuthorities() { return authorities; }
    @Override public String getPassword() { return null; }
    @Override public String getUsername() { return nameId; }
    @Override public boolean isAccountNonExpired() { return true; }
    @Override public boolean isAccountNonLocked() { return true; }
    @Override public boolean isCredentialsNonExpired() { return true; }
    @Override public boolean isEnabled() { return true; }
}

