package com.enterprise.saml.service;

import com.enterprise.saml.config.SamlConfig;
import com.enterprise.saml.exception.SamlException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.core.io.ClassPathResource;
import org.springframework.core.io.FileSystemResource;
import org.springframework.core.io.Resource;
import org.springframework.stereotype.Service;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import javax.annotation.PostConstruct;
import javax.xml.crypto.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.KeyInfo;
import java.io.ByteArrayInputStream;
import java.io.InputStream;
import java.security.Key;
import java.security.PublicKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.util.Iterator;

@Service
public class SamlSignatureValidator {

    private static final Logger logger = LoggerFactory.getLogger(SamlSignatureValidator.class);

    private final SamlConfig samlConfig;
    private X509Certificate idpCertificate;

    public SamlSignatureValidator(SamlConfig samlConfig) {
        this.samlConfig = samlConfig;
    }

    @PostConstruct
    public void init() throws Exception {
        Resource resource;
        String certPath = samlConfig.getIdpCertificatePath();
        if (certPath.startsWith("classpath:")) {
            resource = new ClassPathResource(certPath.substring("classpath:".length()));
        } else {
            resource = new FileSystemResource(certPath);
        }

        try (InputStream is = resource.getInputStream()) {
            CertificateFactory cf = CertificateFactory.getInstance("X.509");
            idpCertificate = (X509Certificate) cf.generateCertificate(is);
        }
        logger.info("Loaded IdP certificate: {}", idpCertificate.getSubjectX500Principal());
    }

    public void validateSignature(Document document) throws SamlException {
        try {
            NodeList signatureNodes = document.getElementsByTagNameNS(
                    XMLSignature.XMLNS, "Signature");

            if (signatureNodes.getLength() == 0) {
                throw new SamlException("No XML Signature found in SAML response");
            }

            // Validate each signature found (response-level and/or assertion-level)
            boolean assertionSigned = false;
            boolean responseSigned = false;

            for (int i = 0; i < signatureNodes.getLength(); i++) {
                Element signatureElement = (Element) signatureNodes.item(i);
                Element parent = (Element) signatureElement.getParentNode();

                if (parent.getLocalName().equals("Assertion")) {
                    assertionSigned = true;
                } else if (parent.getLocalName().equals("Response")) {
                    responseSigned = true;
                }

                validateSingleSignature(signatureElement, document);
            }

            if (samlConfig.isWantAssertionsSigned() && !assertionSigned && !responseSigned) {
                throw new SamlException("Neither response nor assertion is signed");
            }

        } catch (SamlException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlException("Signature validation failed: " + e.getMessage(), e);
        }
    }

    private void validateSingleSignature(Element signatureElement, Document document) throws SamlException {
        try {
            // Use a KeySelector that only trusts our configured IdP certificate
            KeySelector keySelector = new TrustedKeySelector(idpCertificate.getPublicKey());

            DOMValidateContext validateContext = new DOMValidateContext(keySelector, signatureElement);

            // Set ID attribute for proper reference resolution
            setIdAttributes(document, validateContext);

            XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
            XMLSignature signature = factory.unmarshalXMLSignature(validateContext);

            boolean coreValid = signature.validate(validateContext);

            if (!coreValid) {
                // Detailed validation for debugging
                boolean signatureValueValid = signature.getSignatureValue().validate(validateContext);
                logger.error("Signature value validation: {}", signatureValueValid);

                for (Object ref : signature.getSignedInfo().getReferences()) {
                    Reference reference = (Reference) ref;
                    boolean refValid = reference.validate(validateContext);
                    logger.error("Reference [{}] validation: {}", reference.getURI(), refValid);
                }

                throw new SamlException("XML Signature validation failed");
            }

        } catch (SamlException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlException("Error validating signature: " + e.getMessage(), e);
        }
    }

    private void setIdAttributes(Document document, DOMValidateContext context) {
        // Set ID attributes on Response and Assertion elements
        NodeList responses = document.getElementsByTagNameNS(
                "urn:oasis:names:tc:SAML:2.0:protocol", "Response");
        for (int i = 0; i < responses.getLength(); i++) {
            Element el = (Element) responses.item(i);
            if (el.hasAttribute("ID")) {
                context.setIdAttributeNS(el, null, "ID");
            }
        }

        NodeList assertions = document.getElementsByTagNameNS(
                "urn:oasis:names:tc:SAML:2.0:assertion", "Assertion");
        for (int i = 0; i < assertions.getLength(); i++) {
            Element el = (Element) assertions.item(i);
            if (el.hasAttribute("ID")) {
                context.setIdAttributeNS(el, null, "ID");
            }
        }
    }

    /**
     * KeySelector that only accepts our trusted IdP public key.
     * This prevents key substitution attacks where an attacker provides
     * their own certificate in the KeyInfo element.
     */
    private static class TrustedKeySelector extends KeySelector {
        private final PublicKey trustedKey;

        TrustedKeySelector(PublicKey trustedKey) {
            this.trustedKey = trustedKey;
        }

        @Override
        public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose,
                                         AlgorithmMethod method, XMLCryptoContext context)
                throws KeySelectorException {
            return () -> trustedKey;
        }
    }
}

