package com.enterprise.saml.service;

import com.enterprise.saml.exception.SamlException;
import com.enterprise.saml.model.SamlAssertion;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.*;

import javax.xml.XMLConstants;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.time.format.DateTimeParseException;
import java.util.*;

@Service
public class SamlResponseParser {

    private static final Logger logger = LoggerFactory.getLogger(SamlResponseParser.class);

    private static final String SAML_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion";
    private static final String SAML_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol";

    private static final int MAX_RESPONSE_SIZE = 256 * 1024; // 256KB max

    /**
     * Parse SAML response XML securely, preventing XXE and other XML attacks.
     */
    public Document parseSecurely(String xml) throws SamlException {
        if (xml == null || xml.trim().isEmpty()) {
            throw new SamlException("SAML response XML is empty");
        }

        if (xml.length() > MAX_RESPONSE_SIZE) {
            throw new SamlException("SAML response exceeds maximum allowed size");
        }

        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);

            // Prevent XXE attacks
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();
            // Set error handler that doesn't expose internal details
            builder.setErrorHandler(null);

            Document document = builder.parse(
                    new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8)));
            document.getDocumentElement().normalize();

            return document;
        } catch (Exception e) {
            throw new SamlException("Failed to parse SAML response XML: " + e.getMessage(), e);
        }
    }

    /**
     * Validate the SAML Response status and extract the response-level InResponseTo.
     */
    public String validateResponseStatus(Document document) throws SamlException {
        Element responseElement = document.getDocumentElement();

        if (!"Response".equals(responseElement.getLocalName()) ||
                !SAML_PROTOCOL_NS.equals(responseElement.getNamespaceURI())) {
            throw new SamlException("Root element is not a SAML Response");
        }

        // Check status
        NodeList statusNodes = responseElement.getElementsByTagNameNS(SAML_PROTOCOL_NS, "StatusCode");
        if (statusNodes.getLength() == 0) {
            throw new SamlException("No StatusCode found in SAML response");
        }

        Element statusCode = (Element) statusNodes.item(0);
        String statusValue = statusCode.getAttribute("Value");

        if (!"urn:oasis:names:tc:SAML:2.0:status:Success".equals(statusValue)) {
            throw new SamlException("SAML authentication failed with status: " + statusValue);
        }

        return responseElement.getAttribute("InResponseTo");
    }

    /**
     * Extract and parse the SAML Assertion from the response document.
     */
    public SamlAssertion extractAssertion(Document document) throws SamlException {
        NodeList assertionNodes = document.getElementsByTagNameNS(SAML_ASSERTION_NS, "Assertion");

        if (assertionNodes.getLength() == 0) {
            throw new SamlException("No Assertion found in SAML response");
        }

        if (assertionNodes.getLength() > 1) {
            throw new SamlException("Multiple assertions found - only single assertion is supported");
        }

        Element assertionElement = (Element) assertionNodes.item(0);
        SamlAssertion assertion = new SamlAssertion();

        // Parse Issuer
        assertion.setIssuer(extractTextContent(assertionElement, SAML_ASSERTION_NS, "Issuer"));

        // Parse IssueInstant
        String issueInstantStr = assertionElement.getAttribute("IssueInstant");
        if (issueInstantStr != null && !issueInstantStr.isEmpty()) {
            try {
                assertion.setIssueInstant(Instant.parse(issueInstantStr));
            } catch (DateTimeParseException e) {
                throw new SamlException("Invalid IssueInstant format: " + issueInstantStr);
            }
        }

        // Parse Subject
        parseSubject(assertionElement, assertion);

        // Parse Conditions
        parseConditions(assertionElement, assertion);

        // Parse AuthnStatement
        parseAuthnStatement(assertionElement, assertion);

        // Parse Attributes
        assertion.setAttributes(parseAttributes(assertionElement));

        // Extract InResponseTo from SubjectConfirmationData
        parseSubjectConfirmationData(assertionElement, assertion);

        return assertion;
    }

    private void parseSubject(Element assertionElement, SamlAssertion assertion) throws SamlException {
        NodeList subjectNodes = assertionElement.getElementsByTagNameNS(SAML_ASSERTION_NS, "Subject");
        if (subjectNodes.getLength() == 0) {
            throw new SamlException("No Subject found in assertion");
        }

        Element subject = (Element) subjectNodes.item(0);

        NodeList nameIdNodes = subject.getElementsByTagNameNS(SAML_ASSERTION_NS, "NameID");
        if (nameIdNodes.getLength() == 0) {
            throw new SamlException("No NameID found in assertion Subject");
        }

        Element nameIdElement = (Element) nameIdNodes.item(0);
        String nameId = nameIdElement.getTextContent();
        if (nameId == null || nameId.trim().isEmpty()) {
            throw new SamlException("NameID is empty");
        }

        assertion.setNameId(nameId.trim());
        assertion.setNameIdFormat(nameIdElement.getAttribute("Format"));
    }

    private void parseSubjectConfirmationData(Element assertionElement, SamlAssertion assertion) throws SamlException {
        NodeList scDataNodes = assertionElement.getElementsByTagNameNS(
                SAML_ASSERTION_NS, "SubjectConfirmationData");

        if (scDataNodes.getLength() > 0) {
            Element scData = (Element) scDataNodes.item(0);
            assertion.setRecipient(scData.getAttribute("Recipient"));
            assertion.setInResponseTo(scData.getAttribute("InResponseTo"));

            String notOnOrAfterStr = scData.getAttribute("NotOnOrAfter");
            if (notOnOrAfterStr != null && !notOnOrAfterStr.isEmpty()) {
                try {
                    assertion.setNotOnOrAfter(Instant.parse(notOnOrAfterStr));
                } catch (DateTimeParseException e) {
                    throw new SamlException("Invalid NotOnOrAfter in SubjectConfirmationData");
                }
            }
        }
    }

    private void parseConditions(Element assertionElement, SamlAssertion assertion) throws SamlException {
        NodeList conditionsNodes = assertionElement.getElementsByTagNameNS(SAML_ASSERTION_NS, "Conditions");

        if (conditionsNodes.getLength() > 0) {
            Element conditions = (Element) conditionsNodes.item(0);

            String notBefore = conditions.getAttribute("NotBefore");
            if (notBefore != null && !notBefore.isEmpty()) {
                try {
                    assertion.setNotBefore(Instant.parse(notBefore));
                } catch (DateTimeParseException e) {
                    throw new SamlException("Invalid NotBefore format");
                }
            }

            String notOnOrAfter = conditions.getAttribute("NotOnOrAfter");
            if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
                try {
                    assertion.setNotOnOrAfter(Instant.parse(notOnOrAfter));
                } catch (DateTimeParseException e) {
                    throw new SamlException("Invalid NotOnOrAfter format");
                }
            }

            // Parse AudienceRestriction
            NodeList audienceNodes = conditions.getElementsByTagNameNS(SAML_ASSERTION_NS, "Audience");
            if (audienceNodes.getLength() > 0) {
                assertion.setAudience(audienceNodes.item(0).getTextContent().trim());
            }
        }
    }

    private void parseAuthnStatement(Element assertionElement, SamlAssertion assertion) {
        NodeList authnNodes = assertionElement.getElementsByTagNameNS(SAML_ASSERTION_NS, "AuthnStatement");
        if (authnNodes.getLength() > 0) {
            Element authnStatement = (Element) authnNodes.item(0);
            assertion.setSessionIndex(authnStatement.getAttribute("SessionIndex"));

            NodeList authnContextNodes = authnStatement.getElementsByTagNameNS(
                    SAML_ASSERTION_NS, "AuthnContextClassRef");
            if (authnContextNodes.getLength() > 0) {
                assertion.setAuthnContextClassRef(authnContextNodes.item(0).getTextContent().trim());
            }
        }
    }

    private Map<String, List<String>> parseAttributes(Element assertionElement) {
        Map<String, List<String>> attributes = new LinkedHashMap<>();

        NodeList attrStatements = assertionElement.getElementsByTagNameNS(
                SAML_ASSERTION_NS, "AttributeStatement");

        for (int i = 0; i < attrStatements.getLength(); i++) {
            Element attrStatement = (Element) attrStatements.item(i);
            NodeList attrNodes = attrStatement.getElementsByTagNameNS(SAML_ASSERTION_NS, "Attribute");

            for (int j = 0; j < attrNodes.getLength(); j++) {
                Element attrElement = (Element) attrNodes.item(j);
                String attrName = attrElement.getAttribute("Name");

                if (attrName == null || attrName.isEmpty()) {
                    continue;
                }

                List<String> values = new ArrayList<>();
                NodeList valueNodes = attrElement.getElementsByTagNameNS(
                        SAML_ASSERTION_NS, "AttributeValue");

                for (int k = 0; k < valueNodes.getLength(); k++) {
                    String value = valueNodes.item(k).getTextContent();
                    if (value != null) {
                        values.add(value.trim());
                    }
                }

                attributes.put(attrName, values);
            }
        }

        return attributes;
    }

    private String extractTextContent(Element parent, String namespaceURI, String localName) throws SamlException {
        NodeList nodes = parent.getElementsByTagNameNS(namespaceURI, localName);
        if (nodes.getLength() == 0) {
            throw new SamlException("Element " + localName + " not found");
        }
        String text = nodes.item(0).getTextContent();
        return text != null ? text.trim() : null;
    }
}

