// SamlAssertionValidator.java - Assertion validation
// ============================================
package com.enterprise.saml.service;

import com.enterprise.saml.config.SamlConfig;
import com.enterprise.saml.exception.SamlException;
import com.enterprise.saml.model.SamlAssertion;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.time.temporal.ChronoUnit;

@Service
public class SamlAssertionValidator {

    private static final Logger logger = LoggerFactory.getLogger(SamlAssertionValidator.class);

    private final SamlConfig samlConfig;

    public SamlAssertionValidator(SamlConfig samlConfig) {
        this.samlConfig = samlConfig;
    }

    public void validate(SamlAssertion assertion, String expectedInResponseTo) throws SamlException {
        validateIssuer(assertion);
        validateAudience(assertion);
        validateRecipient(assertion);
        validateTimeConditions(assertion);
        validateInResponseTo(assertion, expectedInResponseTo);
        validateNameId(assertion);
    }

    private void validateIssuer(SamlAssertion assertion) throws SamlException {
        if (assertion.getIssuer() == null || assertion.getIssuer().isEmpty()) {
            throw new SamlException("Assertion Issuer is missing");
        }
        if (!samlConfig.getIdpEntityId().equals(assertion.getIssuer())) {
            throw new SamlException("Assertion Issuer mismatch. Expected: " +
                    samlConfig.getIdpEntityId() + ", Got: " + assertion.getIssuer());
        }
    }

    private void validateAudience(SamlAssertion assertion) throws SamlException {
        if (assertion.getAudience() != null && !assertion.getAudience().isEmpty()) {
            if (!samlConfig.getSpEntityId().equals(assertion.getAudience())) {
                throw new SamlException("Audience restriction mismatch. Expected: " +
                        samlConfig.getSpEntityId() + ", Got: " + assertion.getAudience());
            }
        }
    }

    private void validateRecipient(SamlAssertion assertion) throws SamlException {
        if (assertion.getRecipient() != null && !assertion.getRecipient().isEmpty()) {
            if (!samlConfig.getSpAcsUrl().equals(assertion.getRecipient())) {
                throw new SamlException("Recipient mismatch. Expected: " +
                        samlConfig.getSpAcsUrl() + ", Got: " + assertion.getRecipient());
            }
        }
    }

    private void validateTimeConditions(SamlAssertion assertion) throws SamlException {
        Instant now = Instant.now();
        int skewSeconds = samlConfig.getClockSkewSeconds();

        // Validate NotBefore
        if (assertion.getNotBefore() != null) {
            Instant adjustedNotBefore = assertion.getNotBefore().minus(skewSeconds, ChronoUnit.SECONDS);
            if (now.isBefore(adjustedNotBefore)) {
                throw new SamlException("Assertion is not yet valid. NotBefore: " +
                        assertion.getNotBefore() + ", Current time: " + now);
            }
        }

        // Validate NotOnOrAfter
        if (assertion.getNotOnOrAfter() != null) {
            Instant adjustedNotOnOrAfter = assertion.getNotOnOrAfter().plus(skewSeconds, ChronoUnit.SECONDS);
            if (now.isAfter(adjustedNotOnOrAfter) || now.equals(adjustedNotOnOrAfter)) {
                throw new SamlException("Assertion has expired. NotOnOrAfter: " +
                        assertion.getNotOnOrAfter() + ", Current time: " + now);
            }
        }

        // Validate IssueInstant is not too old
        if (assertion.getIssueInstant() != null) {
            Instant maxAge = assertion.getIssueInstant()
                    .plus(samlConfig.getMaxAuthenticationAgeSeconds(), ChronoUnit.SECONDS);
            if (now.isAfter(maxAge)) {
                throw new SamlException("Assertion IssueInstant is too old: " + assertion.getIssueInstant());
            }
        }
    }

    private void validateInResponseTo(SamlAssertion assertion, String expectedInResponseTo) throws SamlException {
        if (expectedInResponseTo != null && !expectedInResponseTo.isEmpty()) {
            if (assertion.getInResponseTo() == null ||
                    !expectedInResponseTo.equals(assertion.getInResponseTo())) {
                throw new SamlException("InResponseTo mismatch. Expected: " +
                        expectedInResponseTo + ", Got: " + assertion.getInResponseTo());
            }
        }
    }

    private void validateNameId(SamlAssertion assertion) throws SamlException {
        if (assertion.getNameId() == null || assertion.getNameId().trim().isEmpty()) {
            throw new SamlException("NameID is missing or empty in assertion");
        }
    }
}

// ============================================
// SamlRequestIdStore.java - Anti-replay protection
// ============================================
package com.enterprise.saml.service;

import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

@Service
public class SamlRequestIdStore {

    private final Map<String, Instant> pendingRequestIds = new ConcurrentHashMap<>();
    private final Map<String, Instant> usedResponseIds = new ConcurrentHashMap<>();

    private static final long EXPIRY_MINUTES = 10;

    public SamlRequestIdStore() {
        ScheduledExecutorService scheduler = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread t = new Thread(r, "saml-id-cleanup");
            t.setDaemon(true);
            return t;
        });
        scheduler.scheduleAtFixedRate(this::cleanup, 5, 5, TimeUnit.MINUTES);
    }

    public void storeRequestId(String requestId) {
        pendingRequestIds.put(requestId, Instant.now());
    }

    public boolean isValidRequestId(String requestId) {
        if (requestId == null) return false;
        Instant stored = pendingRequestIds.remove(requestId);
        if (stored == null) return false;
        return stored.plusSeconds(EXPIRY_MINUTES * 60).isAfter(Instant.now());
    }

    /**
     * Check if a response ID has already been processed (replay detection).
     * Returns true if this is a new (not replayed) response.
     */
    public boolean checkAndStoreResponseId(String responseId) {
        if (responseId == null || responseId.isEmpty()) return false;
        Instant previous = usedResponseIds.putIfAbsent(responseId, Instant.now());
        return previous == null; // true if new, false if already seen
    }

    private void cleanup() {
        Instant cutoff = Instant.now().minusSeconds(EXPIRY_MINUTES * 60);
        pendingRequestIds.entrySet().removeIf(e -> e.getValue().isBefore(cutoff));
        usedResponseIds.entrySet().removeIf(e -> e.getValue().isBefore(cutoff));
    }
}

// ============================================
// SamlAuthenticationService.java - Main authentication service
// ============================================
package com.enterprise.saml.service;

import com.enterprise.saml.config.SamlConfig;
import com.enterprise.saml.exception.SamlException;
import com.enterprise.saml.model.SamlAssertion;
import com.enterprise.saml.model.SamlUserDetails;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Service;
import org.w3c.dom.Document;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpSession;
import java.io.UnsupportedEncodingException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.security.SecureRandom;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class SamlAuthenticationService {

    private static final Logger logger = LoggerFactory.getLogger(SamlAuthenticationService.class);

    private static final String SESSION_ATTR_SAML_USER = "SAML_USER";
    private static final String SESSION_ATTR_SAML_ATTRIBUTES = "SAML_ATTRIBUTES";
    private static final String SESSION_ATTR_REQUEST_ID = "SAML_REQUEST_ID";

    private final SamlConfig samlConfig;
    private final SamlResponseParser responseParser;
    private final SamlSignatureValidator signatureValidator;
    private final SamlAssertionValidator assertionValidator;
    private final SamlRequestIdStore requestIdStore;
    private final SecureRandom secureRandom = new SecureRandom();

    public SamlAuthenticationService(SamlConfig samlConfig,
                                      SamlResponseParser responseParser,
                                      SamlSignatureValidator signatureValidator,
                                      SamlAssertionValidator assertionValidator,
                                      SamlRequestIdStore requestIdStore) {
        this.samlConfig = samlConfig;
        this.responseParser = responseParser;
        this.signatureValidator = signatureValidator;
        this.assertionValidator = assertionValidator;
        this.requestIdStore = requestIdStore;
    }

    /**
     * Generate a SAML AuthnRequest ID and redirect URL.
     */
    public String generateAuthnRequestUrl(HttpServletRequest request) {
        String requestId = "_" + generateSecureId();

        // Store request ID for later validation
        requestIdStore.storeRequestId(requestId);

        // Store in session as well for correlation
        HttpSession session = request.getSession(true);
        session.setAttribute(SESSION_ATTR_REQUEST_ID, requestId);

        // Build a simple AuthnRequest redirect URL
        // In production, you'd construct a proper SAML AuthnRequest XML
        try {
            String samlRequest = buildAuthnRequest(requestId);
            String encoded = Base64.getEncoder().encodeToString(samlRequest.getBytes(StandardCharsets.UTF_8));
            return samlConfig.getIdpSsoUrl() + "?SAMLRequest=" +
                    URLEncoder.encode(encoded, StandardCharsets.UTF_8.name());
        } catch (UnsupportedEncodingException e) {
            throw new RuntimeException("UTF-8 encoding not supported", e);
        }
    }

    /**
     * Process the SAML response received at the ACS endpoint.
     */
    public SamlUserDetails processSamlResponse(String samlResponseBase64, HttpServletRequest request)
            throws SamlException {

        if (samlResponseBase64 == null || samlResponseBase64.trim().isEmpty()) {
            throw new SamlException("SAML response is empty");
        }

        // Decode Base64
        byte[] decodedBytes;
        try {
            decodedBytes = Base64.getDecoder().decode(samlResponseBase64);
        } catch (IllegalArgumentException e) {
            throw new SamlException("Invalid Base64 encoding in SAML response", e);
        }

        String xml = new String(decodedBytes, StandardCharsets.UTF_8);

        // Parse XML securely (XXE protection)
        Document document = responseParser.parseSecurely(xml);

        // Validate response status
        String responseInResponseTo = responseParser.validateResponseStatus(document);

        // Validate XML signature using trusted IdP certificate
        signatureValidator.validateSignature(document);

        // Extract assertion
        SamlAssertion assertion = responseParser.extractAssertion(document);

        // Get expected request ID from session
        HttpSession session = request.getSession(false);
        String expectedRequestId = null;
        if (session != null) {
            expectedRequestId = (String) session.getAttribute(SESSION_ATTR_REQUEST_ID);
        }

        // Validate InResponseTo against stored request ID
        if (expectedRequestId != null) {
            if (!requestIdStore.isValidRequestId(expectedRequestId)) {
                logger.warn("Request ID not found in store or expired: {}", expectedRequestId);
            }
        }

        // Validate assertion (issuer, audience, time conditions, etc.)
        assertionValidator.validate(assertion, expectedRequestId);

        // Anti-replay: check response hasn't been used before
        // Use the assertion's unique attributes for replay detection
        String responseId = document.getDocumentElement().getAttribute("ID");
        if (!requestIdStore.checkAndStoreResponseId(responseId)) {
            throw new SamlException("SAML response replay detected. Response ID: " + responseId);
        }

        // Create authenticated user
        SamlUserDetails userDetails = createUserDetails(assertion);

        // Create Spring Security authentication
        createSecurityContext(userDetails, request);

        // Store user attributes in session
        storeUserAttributesInSession(request, userDetails, assertion);

        logger.info("SAML authentication successful for user: {}", userDetails.getNameId());

        return userDetails;
    }

    private SamlUserDetails createUserDetails(SamlAssertion assertion) {
        // Map SAML attributes to roles/authorities
        List<SimpleGrantedAuthority> authorities = new ArrayList<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        // Map group/role attributes to Spring Security authorities
        List<String> roles = assertion.getAttributes().getOrDefault("Role", Collections.emptyList());
        if (roles.isEmpty()) {
            roles = assertion.getAttributes().getOrDefault(
                    "http://schemas.microsoft.com/ws/2008/06/identity/claims/role",
                    Collections.emptyList());
        }

        for (String role : roles) {
            String sanitizedRole = role.trim().toUpperCase().replaceAll("[^A-Z0-9_]", "_");
            if (!sanitizedRole.startsWith("ROLE_")) {
                sanitizedRole = "ROLE_" + sanitizedRole;
            }
            authorities.add(new SimpleGrantedAuthority(sanitizedRole));
        }

        return new SamlUserDetails(
                assertion.getNameId(),
                assertion.getSessionIndex(),
                assertion.getAttributes(),
                authorities
        );
    }

    private void createSecurityContext(SamlUserDetails userDetails, HttpServletRequest request) {
        UsernamePasswordAuthenticationToken authentication =
                new UsernamePasswordAuthenticationToken(
                        userDetails,
                        null,
                        userDetails.getAuthorities()
                );

        SecurityContextHolder.getContext().setAuthentication(authentication);

        // Invalidate old session and create new one to prevent session fixation
        HttpSession oldSession = request.getSession(false);
        Map<String, Object> preservedAttributes = new HashMap<>();

        if (oldSession != null) {
            // Preserve non-SAML session attributes if needed
            Enumeration<String> attrNames = oldSession.getAttributeNames();
            while (attrNames.hasMoreElements()) {
                String name = attrNames.nextElement();
                if (!name.startsWith("SAML_")) {
                    preservedAttributes.put(name, oldSession.getAttribute(name));
                }
            }
            oldSession.invalidate();
        }

        HttpSession newSession = request.getSession(true);
        preservedAttributes.forEach(newSession::setAttribute);
    }

    private void storeUserAttributesInSession(HttpServletRequest request,
                                               SamlUserDetails userDetails,
                                               SamlAssertion assertion) {
        HttpSession session = request.getSession();

        session.setAttribute(SESSION_ATTR_SAML_USER, userDetails);
        session.setAttribute(SESSION_ATTR_SAML_ATTRIBUTES, userDetails.getAttributes());

        // Store commonly used attributes individually for convenience
        storeAttributeIfPresent(session, "email", assertion, 
                "email", "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress");
        storeAttributeIfPresent(session, "firstName", assertion,
                "firstName", "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname");
        storeAttributeIfPresent(session, "lastName", assertion,
                "lastName", "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname");
        storeAttributeIfPresent(session, "displayName", assertion,
                "displayName", "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name");

        // Set reasonable session timeout
        session.setMaxInactiveInterval(3600); // 1 hour
    }

    private void storeAttributeIfPresent(HttpSession session, String sessionKey,
                                          SamlAssertion assertion, String... attributeNames) {
        for (String attrName : attributeNames) {
            List<String> values = assertion.getAttributes().get(attrName);
            if (values != null && !values.isEmpty()) {
                session.setAttribute(sessionKey, values.get(0));
                return;
            }
        }
    }

    private String buildAuthnRequest(String requestId) {
        Instant now = Instant.now();
        return "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                "<samlp:AuthnRequest xmlns:samlp=\"urn:oasis:names:tc:SAML:2.0:protocol\" " +
                "xmlns:saml=\"urn:oasis:names:tc:SAML:2.0:assertion\" " +
                "ID=\"" + escapeXml(requestId) + "\" " +
                "Version=\"2.0\" " +
                "IssueInstant=\"" + now.toString() + "\" " +
                "Destination=\"" + escapeXml(samlConfig.getIdpSsoUrl()) + "\" " +
                "AssertionConsumerServiceURL=\"" + escapeXml(samlConfig.getSpAcsUrl()) + "\" " +
                "ProtocolBinding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\">" +
                "<saml:Issuer>" + escapeXml(samlConfig.getSpEntityId()) + "</saml:Issuer>" +
                "<samlp:NameIDPolicy Format=\"urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress\" " +
                "AllowCreate=\"false\"/>" +
                "</samlp:AuthnRequest>";
    }

    private String generateSecureId() {
        byte[] bytes = new byte[20];
        secureRandom.nextBytes(bytes);
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }

    private String escapeXml(String input) {
        if (input == null) return "";
        return input.replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&apos;");
    }
}

// ============================================
// SamlController.java - Web endpoints
// ============================================
package com.enterprise.saml.controller;

import com.enterprise.saml.exception.SamlException;
import com.enterprise.saml.model.SamlUserDetails;
import com.enterprise.saml.service.SamlAuthenticationService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.*;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;

@Controller
public class SamlController {

    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);

    private final SamlAuthenticationService authenticationService;

    public SamlController(SamlAuthenticationService authenticationService) {
        this.authenticationService = authenticationService;
    }

    /**
     * Initiate SAML login - redirect to IdP.
     */
    @GetMapping("/saml/login")
    public void initiateLogin(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String redirectUrl = authenticationService.generateAuthnRequestUrl(request);
        response.sendRedirect(redirectUrl);
    }

    /**
     * Assertion Consumer Service (ACS) endpoint - receives SAML response via HTTP POST.
     */
    @PostMapping("/saml/acs")
    public String assertionConsumerService(
            @RequestParam("SAMLResponse") String samlResponse,
            HttpServletRequest request,
            Model model) {

        try {
            SamlUserDetails userDetails = authenticationService.processSamlResponse(samlResponse, request);

            logger.info("User authenticated via SAML: {}", userDetails.getNameId());

            return "redirect:/dashboard";

        } catch (SamlException e) {
            logger.error("SAML authentication failed: {}", e.getMessage());
            model.addAttribute("error", "Authentication failed. Please try again.");
            return "error";
        }
    }

    /**
     * Dashboard - protected page showing user info.
     */
    @GetMapping("/dashboard")
    public String dashboard(HttpServletRequest request, Model model) {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();

        if (auth == null || !(auth.getPrincipal() instanceof SamlUserDetails)) {
            return "redirect:/saml/login";
        }

        SamlUserDetails user = (SamlUserDetails) auth.getPrincipal();
        model.addAttribute("user", user);
        model.addAttribute("nameId", user.getNameId());
        model.addAttribute("attributes", user.getAttributes());
        model.addAttribute("authorities", user.getAuthorities());

        // Also retrieve from session
        HttpSession session = request.getSession(false);
        if (session != null) {
            model.addAttribute("email", session.getAttribute("email"));
            model.addAttribute("firstName", session.getAttribute("firstName"));
            model.addAttribute("lastName", session.getAttribute("lastName"));
            model.addAttribute("displayName", session.getAttribute("displayName"));
        }

        return "dashboard";
    }

    /**
     * Logout endpoint.
     */
    @GetMapping("/saml/logout")
    public String logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }
        SecurityContextHolder.clearContext();
        return "redirect:/";
    }

    /**
     * Metadata endpoint for SP configuration.
     */
    @GetMapping(value = "/saml/metadata", produces = "application/xml")
    @ResponseBody
    public String metadata() {
        // Return SP metadata - in production, generate this properly
        return "<?xml version=\"1.0\"?>" +
                "<md:EntityDescriptor xmlns:md=\"urn:oasis:names:tc:SAML:2.0:metadata\">" +
                "</md:EntityDescriptor>";
    }
}

// ============================================
// SecurityConfig.java - Spring Security configuration
// ============================================
package com.enterprise.saml.config;

import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;

@Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            .authorizeRequests()
                .antMatchers("/saml/acs", "/saml/login", "/saml/metadata", "/", "/error").permitAll()
                .anyRequest().authenticated()
            .and()
            .csrf()
                // SAML ACS endpoint receives POST from IdP, so we need to exempt it from CSRF
                // but we validate InResponseTo and replay protection instead
                .ignoringAntMatchers("/saml/acs")
            .and()
            .headers()
                .frameOptions().deny()
                .contentTypeOptions().and()
                .xssProtection().block(true).and()
                .httpStrictTransportSecurity().includeSubDomains(true).maxAgeInSeconds(31536000)
            .and().and()
            .sessionManagement()
                .sessionFixation().newSession()
                .maximumSessions(1)
                .expiredUrl("/saml/login");
    }
}

